package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClass;
  private static Class<?> nonRecordClass;

  @BeforeAll
  static void setup() {
    // Use java.lang.Record class as a stand-in for record class (Java 16+)
    recordClass = java.lang.Record.class;
    nonRecordClass = NonRecordSample.class;
  }

  @Test
  void testIsRecord_withRecordClass_returnsTrue() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
      recordHelperField.setAccessible(true);
      Object mockRecordHelper = mock(recordHelperField.getType());
      when(mockRecordHelper.getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, recordClass)).thenReturn(true);
      // Instead of using invoke above, we mock the method via Mockito directly:
      // But since mockRecordHelper is of type Object, cast to proper type:
      // So better to cast:
      // Actually simpler:
      Object recordHelperMock = mock(recordHelperField.getType());
      // Use Mockito to stub isRecord method:
      // Cast to the interface or class is not possible here without import, so use reflection to stub:
      // But Mockito cannot stub methods on Object via reflection easily.
      // So use Mockito's when on mockRecordHelper:
      // Use Mockito's doReturn:
      // But better to cast:
      // So let's get the class of RECORD_HELPER and cast:
      Class<?> recordHelperClass = recordHelperField.getType();
      Object recordHelperMock2 = mock(recordHelperClass);
      try {
        var method = recordHelperClass.getMethod("isRecord", Class.class);
        when(method.invoke(recordHelperMock2, recordClass)).thenReturn(true);
      } catch (Exception e) {
        fail("Reflection error: " + e.getMessage());
      }
      recordHelperField.set(null, recordHelperMock2);

      boolean result = ReflectionHelper.isRecord(recordClass);
      assertTrue(result);
      // Verify the isRecord method was called on recordHelperMock2:
      try {
        var method = recordHelperClass.getMethod("isRecord", Class.class);
        verify(recordHelperMock2).getClass().getMethod("isRecord", Class.class);
      } catch (NoSuchMethodException e) {
        fail("Reflection error: " + e.getMessage());
      }
    } catch (Exception e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  @Test
  void testIsRecord_withNonRecordClass_returnsFalse() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
      recordHelperField.setAccessible(true);
      Class<?> recordHelperClass = recordHelperField.getType();
      Object recordHelperMock = mock(recordHelperClass);
      try {
        var method = recordHelperClass.getMethod("isRecord", Class.class);
        when(method.invoke(recordHelperMock, nonRecordClass)).thenReturn(false);
      } catch (Exception e) {
        fail("Reflection error: " + e.getMessage());
      }
      recordHelperField.set(null, recordHelperMock);

      boolean result = ReflectionHelper.isRecord(nonRecordClass);
      assertFalse(result);
      try {
        var method = recordHelperClass.getMethod("isRecord", Class.class);
        verify(recordHelperMock).getClass().getMethod("isRecord", Class.class);
      } catch (NoSuchMethodException e) {
        fail("Reflection error: " + e.getMessage());
      }
    } catch (Exception e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  // Dummy non-record class
  public static class NonRecordSample {
    private String name;
    private int id;
  }
}
